/**
 * Objek global untuk mengelola fungsionalitas format.
 * Mengandung fungsi-fungsi helper untuk memformat data seperti tanggal dan angka.
 */
const FormatHelper = {
    /**
     * Memformat tanggal dari YYYY-MM-DD atau DD-MM-YYYY menjadi DD-MM-YYYY.
     *
     * @param {string} dateString String tanggal yang akan diformat.
     * @returns {string} Tanggal yang diformat atau string asli jika format tidak dikenali.
     */
    formatTanggal: function (dateString) {
        if (!dateString) return "";
        const dateParts = dateString.split("-");
        if (dateParts.length !== 3) return dateString;

        const [part1, part2, part3] = dateParts;
        const isYYYYMMDD =
            part1.length === 4 && part2.length === 2 && part3.length === 2;
        const isDDMMYYYY =
            part1.length === 2 && part2.length === 2 && part3.length === 4;

        if (isYYYYMMDD) {
            return `${part3}.${part2}.${part1}`;
        } else if (isDDMMYYYY) {
            return dateString;
        } else {
            return dateString;
        }
    },

    /**
     * Memformat tanggal dari Date menjadi "0 tahun 11 bulan 21 hari".
     * @param {Date} tglSekarang
     * @param {Date} tglAkhir
     * @returns
     */
    formatHitungMundur: function (tglSekarang, tglAkhir) {
        if (!tglSekarang || !tglAkhir) return "-";

        let tahun = tglAkhir.getFullYear() - tglSekarang.getFullYear();
        let bulan = tglAkhir.getMonth() - tglSekarang.getMonth();
        let hari = tglAkhir.getDate() - tglSekarang.getDate();
        if (hari < 0) {
            bulan--;
            const prevMonth = new Date(
                tglAkhir.getFullYear(),
                tglAkhir.getMonth(),
                0
            );
            hari += prevMonth.getDate();
        }
        if (bulan < 0) {
            tahun--;
            bulan += 12;
        }
        const teks = `${Math.max(tahun, 0)} tahun ${Math.max(
            bulan,
            0
        )} bulan ${Math.max(hari, 0)} hari`;

        const diffHari = Math.floor(
            (tglAkhir - tglSekarang) / (1000 * 60 * 60 * 24)
        );
        const sudahLewat = diffHari < 0;
        if (sudahLewat) {
            return `<span class="text-danger">Berakhir</span>`;
        }
        if (diffHari <= 7) {
            return `<span class="text-danger">${teks}</span>`;
        }
        return teks;
    },
};
